export const LANGS = ["de", "en", "es", "fr", "it", "pt"] as const;
export type Lang = (typeof LANGS)[number];

export function detectLang(): Lang {
  try {
    const s = localStorage.getItem("meetUiLang");
    if (s && (LANGS as readonly string[]).includes(s)) return s as Lang;
  } catch {
    /* ignore */
  }
  const n = (navigator.language || "de").toLowerCase();
  const m = LANGS.find((c) => n.startsWith(c));
  return m || "de";
}

/** Translate a German source string into the active language (German = identity). */
export function translate(lang: Lang, de: string): string {
  return lang === "de" ? de : (I18N[lang] && I18N[lang][de]) || de;
}

type LangCtx = { lang: Lang; setLang: (l: Lang) => void; t: (de: string) => string };
const Ctx = createContext<LangCtx | null>(null);

export function LangProvider({ children }: { children: ReactNode }) {
  const [lang, setLangState] = useState<Lang>(detectLang);
  const setLang = useCallback((l: Lang) => {
    setLangState(l);
    try {
      localStorage.setItem("meetUiLang", l);
    } catch {
      /* ignore */
    }
    try {
      document.documentElement.lang = l;
    } catch {
      /* ignore */
    }
  }, []);
  const t = useCallback((de: string) => translate(lang, de), [lang]);
  return <Ctx.Provider value={{ lang, setLang, t }}>{children}</Ctx.Provider>;
}

export function useI18n(): LangCtx {
  const c = useContext(Ctx);
  if (!c) throw new Error("useI18n must be used within LangProvider");
  return c;
}
